1	type Customer = {
2	  yearsAsCustomer: number;
3	  quoteCount: number;
4	};
5	
6	type Item = {
7	  type: string;
8	  material: string;
9	  enchantment: number;
10	  cursed: boolean;
11	};
12	
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	};
20	
21	const PROCESSING_FEE = 5;
22	const FIRST_INSURANCE_RATE = 0.1;
23	
24	const COMPONENT_BLOCK_SIZE = 3;
25	const COMPONENT_BLOCK_PREMIUM = 60;
26	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
27	
28	const componentPremium = (type: string, count: number): number =>
29	  count === COMPONENT_BLOCK_SIZE
30	    ? COMPONENT_BLOCK_PREMIUM
31	    : count * BASE_PREMIUMS[type];
32	
33	export function quote(customer: Customer, items: Item[]): number {
34	  if (items.length === 0) return PROCESSING_FEE;
35	
36	  let basePremium = 0;
37	  const componentCounts: Record<string, number> = {};
38	
39	  for (const item of items) {
40	    if (COMPONENT_TYPES.has(item.type)) {
41	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
42	    } else {
43	      basePremium += BASE_PREMIUMS[item.type];
44	    }
45	  }
46	
47	  for (const type of Object.keys(componentCounts)) {
48	    basePremium += componentPremium(type, componentCounts[type]);
49	  }
50	
51	  return basePremium + basePremium * FIRST_INSURANCE_RATE + PROCESSING_FEE;
52	}
53	
54	export function claim() {
55	  return undefined;
56	}
